import { useState } from "react";

const toppings = [
  { emoji: "🍄", price: 40 },
  { emoji: "🧀", price: 45 },
  { emoji: "🌽", price: 30 },
  { emoji: "🫒", price: 35 },
  { emoji: "🧅", price: 20 },
  { emoji: "🌶️", price: 25 },
];

export default function PizzaBuilder() {
  const [pizza, setPizza] = useState([]);

  function dropTopping(e) {
    e.preventDefault();

    const rect = e.currentTarget.getBoundingClientRect();

    const topping = JSON.parse(
      e.dataTransfer.getData("topping")
    );

    setPizza([
      ...pizza,
      {
        ...topping,
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      },
    ]);
  }

  const total =
    299 + pizza.reduce((sum, t) => sum + t.price, 0);

  return (
    <div className="container">
      <h1>🍕 Pizza Builder</h1>

      <h2>Total: ₹{total}</h2>

      <div
        onDragOver={(e) => e.preventDefault()}
        onDrop={dropTopping}
        style={{
          position: "relative",
          width: 350,
          height: 350,
        }}
      >
        <img
          src="https://www.shutterstock.com/image-illustration/pizza-no-topping-260nw-2685328587.jpg"
          width="350"
          alt="Pizza"
        />

        {pizza.map((topping, i) => (
          <span
            key={i}
            style={{
              position: "absolute",
              left: topping.x,
              top: topping.y,
              transform: "translate(-50%, -50%)",
              fontSize: "2rem",
            }}
          >
            {topping.emoji}
          </span>
        ))}
      </div>

      <h2>Toppings</h2>

      <div>
        {toppings.map((topping) => (
          <span
            key={topping.emoji}
            draggable
            onDragStart={(e) =>
              e.dataTransfer.setData(
                "topping",
                JSON.stringify(topping)
              )
            }
            style={{
              fontSize: "2rem",
              cursor: "grab",
              margin: "0.5rem",
            }}
          >
            {topping.emoji}
          </span>
        ))}
      </div>
    </div>
  );
}
